import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // [[1,4,5],[1,3,4],[2,6]] -> [1,1,2,3,4,4,5,6]
        List<List<Integer>> input = List.of(
            List.of(1, 4, 5),
            List.of(1, 3, 4),
            List.of(2, 6)
        );
        assertEquals(List.of(1, 1, 2, 3, 4, 4, 5, 6), new Solution().mergeKSortedLists(input));
    }

    @Test
    void singleSource() {
        // k=1: output must equal the single source unchanged
        List<List<Integer>> input = List.of(List.of(3, 6, 9));
        assertEquals(List.of(3, 6, 9), new Solution().mergeKSortedLists(input));
    }

    @Test
    void emptyInnerList() {
        // src1 is empty — must not crash
        List<List<Integer>> input = List.of(
            List.of(1, 3),
            List.of(),
            List.of(2, 4)
        );
        assertEquals(List.of(1, 2, 3, 4), new Solution().mergeKSortedLists(input));
    }

    @Test
    void emptyOuterList() {
        // no sources at all -> empty result
        assertEquals(List.of(), new Solution().mergeKSortedLists(List.of()));
    }

    @Test
    void allSourcesSingleElement() {
        // each list contributes exactly one element
        List<List<Integer>> input = List.of(
            List.of(8),
            List.of(2),
            List.of(5)
        );
        assertEquals(List.of(2, 5, 8), new Solution().mergeKSortedLists(input));
    }

    @Test
    void tiebreakerBySourceIndex() {
        // src0 and src1 both start with 4; src0 wins first
        List<List<Integer>> input = List.of(
            List.of(4, 7),
            List.of(4, 9)
        );
        assertEquals(List.of(4, 4, 7, 9), new Solution().mergeKSortedLists(input));
    }

    @Test
    void manyEmptySourcesOneNonEmpty() {
        // only the last source has elements
        List<List<Integer>> input = List.of(
            List.of(),
            List.of(),
            List.of(1, 2, 3)
        );
        assertEquals(List.of(1, 2, 3), new Solution().mergeKSortedLists(input));
    }
}
